```plantuml
@startuml
skinparam backgroundColor transparent
skinparam packageStyle folder

package rugged #EAE8D5 {
  package raster #D5E8D5 {
    interface Tile {
      + interpolateElevation(φ, λ)
      + pixelIntersection(NormalizedGeodeticPoint, los, φ index, λ index)
    }
  }

  package intersection #D5E8D5 {
    interface IntersectionAlgorithm {
      + intersection(ellipsoid, position, los)
      + refineIntersection(ellipsoid, position, los, closeGuess)
    }
  }

  package utils #D5E8D5 {
    class ExtendedEllipsoid {
      + pointAtLatitude(position, los, φ, closereference)
      + pointAtLongitude(position, los, λ)
      + pointAtAltitude(position, los, h)
      + pointOnGround(position, los)
    }
    class SpacecraftToObservedBody {
    }
  }

  package api #D5E8D5 {
    class Rugged {
      + directLocation(sensorName, line)
    }
  }

  package linesensor #D5E8D5 {
    class LineSensor {
    }
  }
}

package mission {
  package specific #D5E8D5 {
    class UserMain {
    }
  }
}

IntersectionAlgorithm -up-> Tile : evaluate DEM
IntersectionAlgorithm -down-> ExtendedEllipsoid : compute grid points crossings
Rugged -up-> IntersectionAlgorithm : delegate DEM intersection\n1
Rugged -up-> ExtendedEllipsoid : convert geodetic points
Rugged -up-> SpacecraftToObservedBody : convert positions/directions
Rugged -down-> LineSensor : getLOS(date, pixel)
Rugged -down-> LineSensor : getDate(line)
UserMain -down-> Rugged

@enduml
```
